CREATE TABLE households (id TEXT PRIMARY KEY, name TEXT NOT NULL, created_at TEXT NOT NULL);
CREATE TABLE members (household_id TEXT NOT NULL, email TEXT NOT NULL, role TEXT NOT NULL CHECK (role IN ('owner','caregiver')), created_at TEXT NOT NULL, PRIMARY KEY (household_id,email));
CREATE TABLE child_profiles (id TEXT PRIMARY KEY, household_id TEXT NOT NULL UNIQUE, display_name TEXT NOT NULL, birth_date TEXT, notes TEXT, created_at TEXT NOT NULL, updated_at TEXT NOT NULL);
CREATE TABLE ingredients (id TEXT PRIMARY KEY, household_id TEXT NOT NULL, name TEXT NOT NULL, category TEXT, status TEXT NOT NULL CHECK (status IN ('not_tried','planned','testing','tolerated','suspected_reaction')), notes TEXT, created_at TEXT NOT NULL, updated_at TEXT NOT NULL);
CREATE TABLE cube_lots (id TEXT PRIMARY KEY, household_id TEXT NOT NULL, ingredient_id TEXT NOT NULL, made_at TEXT NOT NULL, expires_at TEXT, initial_count INTEGER NOT NULL CHECK (initial_count >= 0), remaining_count INTEGER NOT NULL CHECK (remaining_count >= 0 AND remaining_count <= initial_count), grams_per_cube REAL, storage_location TEXT, created_at TEXT NOT NULL, updated_at TEXT NOT NULL);
CREATE TABLE combinations (id TEXT PRIMARY KEY, household_id TEXT NOT NULL, name TEXT NOT NULL, stage TEXT, texture TEXT, notes TEXT, created_at TEXT NOT NULL, updated_at TEXT NOT NULL);
CREATE TABLE combination_items (combination_id TEXT NOT NULL, ingredient_id TEXT NOT NULL, cube_count REAL NOT NULL CHECK (cube_count > 0), PRIMARY KEY (combination_id, ingredient_id));
CREATE TABLE meal_plan_slots (id TEXT PRIMARY KEY, household_id TEXT NOT NULL, date TEXT NOT NULL, meal_type TEXT NOT NULL CHECK (meal_type IN ('아침','점심','저녁')), target_type TEXT NOT NULL CHECK (target_type IN ('combination','ingredient')), combination_id TEXT, ingredient_id TEXT, cube_count REAL, status TEXT NOT NULL DEFAULT 'planned', created_at TEXT NOT NULL, updated_at TEXT NOT NULL);
CREATE TABLE events (id TEXT PRIMARY KEY, household_id TEXT NOT NULL, actor_email TEXT NOT NULL, source TEXT NOT NULL CHECK (source IN ('manual','ai','system')), type TEXT NOT NULL, payload_json TEXT NOT NULL, before_json TEXT, after_json TEXT, created_at TEXT NOT NULL, undo_event_id TEXT);
CREATE TABLE ai_commands (id TEXT PRIMARY KEY, household_id TEXT NOT NULL, actor_email TEXT NOT NULL, raw_text TEXT NOT NULL, parsed_intent_json TEXT, validation_result_json TEXT, status TEXT NOT NULL CHECK (status IN ('auto_applied','pending_approval','rejected','rolled_back')), event_id TEXT, dedupe_key TEXT, model_name TEXT, created_at TEXT NOT NULL);
CREATE TABLE approval_requests (id TEXT PRIMARY KEY, household_id TEXT NOT NULL, actor_email TEXT NOT NULL, request_type TEXT NOT NULL, payload_json TEXT NOT NULL, status TEXT NOT NULL CHECK (status IN ('pending','approved','rejected')), reviewer_email TEXT, created_at TEXT NOT NULL, reviewed_at TEXT);
CREATE INDEX idx_cube_lots_household_ingredient ON cube_lots(household_id, ingredient_id);
CREATE INDEX idx_events_household_created ON events(household_id, created_at);
CREATE INDEX idx_ai_commands_dedupe ON ai_commands(household_id, dedupe_key, created_at);
